import ReactDOM from "react-dom/client";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import { Link } from "react-router-dom";
// import logo from './logo.svg';
import './App.css';
import Register from './register';

const App = () => {

  return (
    <div className="App">
      {/* 標頭 */}
      <nav class="menu">
        <ul class="subMenu">
          <li class="mainLink"><a href="https://www.vscinemas.com.tw/vsweb/#" class="firstMenu">影城介紹</a>
            <ul class="sublink">
              <li><a href="https://www.vscinemas.com.tw/vsweb/theater/index.aspx">威秀影城</a></li>
              <li><a href="https://www.vscinemas.com.tw/vsweb/theater/detail2.aspx?id=23">MOVIE</a></li>
            </ul>
          </li>
        </ul>
      </nav>

      <Register />

    </div>
  );
}

export default App;
